// src/components/TelaAlunos.js
import React, { useState, useEffect } from "react";
import axios from "axios";
import Modal from './Modal';
import FormAluno from './FormAluno';

export default function TelaAlunos() {
  const [alunos, setAlunos] = useState([]);
  const [carregando, setCarregando] = useState(true);
  const [mostrarModal, setMostrarModal] = useState(false);
  const [alunoEditando, setAlunoEditando] = useState(null);

  // Carregar lista de alunos
  useEffect(() => {
    setCarregando(true);
    axios.get('/api/alunos')
      .then(res => {
        setAlunos(res.data);
        setCarregando(false);
      })
      .catch(() => setCarregando(false));
  }, []);

  function recarregarAlunos() {
    setCarregando(true);
    axios.get('/api/alunos')
      .then(res => {
        setAlunos(res.data);
        setCarregando(false);
      })
      .catch(() => setCarregando(false));
  }

  function onEditar(aluno) {
    setAlunoEditando(aluno);
    setMostrarModal(true);
  }

  function onNovo() {
    recarregarAlunos();
  }

  function onFecharModal() {
    setAlunoEditando(null);
    setMostrarModal(false);
  }

  if (carregando) return <p className="text-center py-8">Carregando alunos...</p>;
  if (alunos.length === 0) return <p className="text-center py-8">Nenhum aluno cadastrado.</p>;

  return (
    <div className="mt-4 px-4 md:px-8">
      <div className="flex justify-between items-center mb-2">
       {/*<h2 className="text-xl font-semibold text-[#1d3557]">Lista de Alunos</h2>*/}
        <button
          className="bg-green-500 text-white px-4 py-2 rounded-full hover:bg-green-600 transition"
          onClick={() => setMostrarModal(true)}
        >
          Novo Aluno
        </button>

      </div>

      {/* Cabeçalho: visível apenas em md+ */}
      <div className="
        hidden md:grid md:grid-cols-6 gap-x-4
        px-5 py-3 bg-gray-100 rounded-t-xl
        font-semibold text-gray-600 mb-2
      ">
        <span className="truncate">Nome</span>
        <span className="truncate">RA</span>
        <span className="truncate">Usuário</span>
        <span className="truncate">Perfil</span>
        <span className="truncate">Período</span>
        <span className="text-right">Ações</span>
      </div>

      {/* Lista de alunos */}
      <ul className="space-y-3">
        {alunos.map(a => (
          <li
            key={a.id}
            className="
              flex flex-col md:grid md:grid-cols-6 gap-y-2 gap-x-4
              bg-gray-50 rounded-xl px-4 md:px-5 py-3
              shadow-sm hover:bg-gray-100 transition
            "
          >
            {/* Coluna: Nome */}
            <div className="w-full font-medium text-gray-800 truncate">
              {a.nome}
            </div>

            {/* Coluna: RA */}
            <div className="w-full text-gray-600 truncate">
              {a.ra}
            </div>

            {/* Coluna: Usuário */}
            <div className="w-full text-gray-600 truncate">
              {a.usuario}
            </div>

            {/* Coluna: Perfil (role) */}
            <div className="w-full text-gray-600 truncate">
              {a.role}
            </div>

            {/* Coluna: Período */}
            <div className="w-full text-gray-600 truncate">
              {a.periodo_nome} {a.turno}
            </div>

            {/* Coluna: Ações (botões) */}
            <div className="flex md:justify-end items-center space-x-2">
              <button
                onClick={() => onEditar(a)}
                className="
                  px-3 py-1 rounded-lg bg-blue-100 text-blue-800
                  hover:bg-blue-200 font-semibold transition
                "
              >
                Editar
              </button>
              <button
                onClick={() => {
                  if (window.confirm('Tem certeza que deseja deletar este aluno?')) {
                    axios.delete(`/api/alunos/${a.id}`)
                      .then(() => recarregarAlunos());
                  }
                }}
                className="
                  px-3 py-1 rounded-lg bg-red-100 text-red-700
                  hover:bg-red-200 font-semibold transition
                "
              >
                Deletar
              </button>
            </div>
          </li>
        ))}
      </ul>

      {/* Modal de Cadastro/Edição */}
      {mostrarModal && (
        <Modal isOpen={mostrarModal} onRequestClose={onFecharModal}>
          <FormAluno
            alunoEditando={alunoEditando}
            onNovoAluno={onNovo}
            onFimEdicao={onFecharModal}
          />
        </Modal>
      )}
    </div>
  );
}
